        XCTAssertEqual(cfg.sensitivity, 1.0)
    }

    func testRangeBoundariesRejected() {
        let store = InMemoryKVStore([
            "sensitivity": 100.0,
            "debounceEntryFrames": 1000,
            "pinchStartDistance": 10.0,
            "degradedConfidenceThreshold": 1.5,
            "oneEuroBeta": -0.1,
        ])
        let cfg = Config.load(from: store)
